Module[{b3, kGimel, sumMnu, planckBound, oscLower, desiCentral, desiSigma, tension, inWindow, status},
  (* G2 manifold Pillar Seeds *)
  b3 = 24;
  kGimel = b3/2 + 1/Pi; (* = 12.31831... from FormulasRegistry *)

  (* Hopf fibration formula: Sum(m_nu) = k_gimel / (2*Pi*b3) *)
  sumMnu = kGimel / (2*Pi*b3);

  (* Experimental bounds *)
  planckBound = 0.12;   (* eV, Planck+BAO 2018, 95% CL *)
  oscLower = 0.058;      (* eV, oscillation floor NH from NuFit 6.0 *)
  desiCentral = 0.072;   (* eV, DESI+CMB+BAO 2024 reference *)
  desiSigma = 0.02;      (* eV, approximate 1-sigma *)

  tension = Abs[sumMnu - desiCentral] / desiSigma;
  inWindow = (oscLower < sumMnu < planckBound);
  status = If[inWindow, "LOCKED", "FAILED"];

  {N[sumMnu, 4], N[tension, 2], status}
]
